package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonNull;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

    private JsonTreeReader jsonTreeReader;

    @BeforeEach
    public void setUp() throws Exception {
        // Create a JsonTreeReader instance with a JsonNull element (minimal valid JsonElement)
        jsonTreeReader = new JsonTreeReader(JsonNull.INSTANCE);

        // Use reflection to set private fields stack, stackSize, pathIndices to simulate state

        // Set stackSize to 1 to test increment of pathIndices in nextNull()
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 1);

        // Initialize pathIndices array with zeros
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndices = new int[32];
        pathIndices[0] = 0;
        pathIndicesField.set(jsonTreeReader, pathIndices);

        // Initialize stack with one element (dummy)
        Field stackField = JsonTreeReader.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        Object[] stack = new Object[32];
        stack[0] = JsonNull.INSTANCE;
        stackField.set(jsonTreeReader, stack);
    }

    @Test
    public void testNextNull_stackSizeGreaterThanZero() throws Exception {
        // We need to spy on jsonTreeReader to verify private expect and popStack are called correctly
        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Mock expect(JsonToken.NULL) to do nothing (since it is private)
        Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
        expectMethod.setAccessible(true);
        doNothing().when(spyReader).expect(JsonToken.NULL);

        // Mock popStack() to simulate popping stack and decrement stackSize
        Method popStackMethod = JsonTreeReader.class.getDeclaredMethod("popStack");
        popStackMethod.setAccessible(true);
        doAnswer(invocation -> {
            // Decrement stackSize field by 1
            Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
            stackSizeField.setAccessible(true);
            int currentSize = stackSizeField.getInt(spyReader);
            stackSizeField.setInt(spyReader, currentSize - 1);
            // Return dummy popped object
            return JsonNull.INSTANCE;
        }).when(spyReader).popStack();

        // Before calling nextNull, pathIndices[0] is 0
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndicesBefore = (int[]) pathIndicesField.get(spyReader);
        assertEquals(0, pathIndicesBefore[0]);

        // Call nextNull()
        spyReader.nextNull();

        // Verify expect was called with JsonToken.NULL
        verify(spyReader).expect(JsonToken.NULL);

        // Verify popStack was called
        verify(spyReader).popStack();

        // After nextNull, stackSize should be 0 (decremented by popStack mock)
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        int stackSizeAfter = stackSizeField.getInt(spyReader);
        assertEquals(0, stackSizeAfter);

        // Since stackSize after popStack is now 0, pathIndices increment should NOT happen
        int[] pathIndicesAfter = (int[]) pathIndicesField.get(spyReader);
        assertEquals(0, pathIndicesAfter[0]);
    }

    @Test
    public void testNextNull_stackSizeZero() throws Exception {
        // Set stackSize to 0 to test that pathIndices increment does not occur
        Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeField.setAccessible(true);
        stackSizeField.setInt(jsonTreeReader, 0);

        JsonTreeReader spyReader = spy(jsonTreeReader);

        // Mock expect to do nothing
        doNothing().when(spyReader).expect(JsonToken.NULL);

        // Mock popStack to decrement stackSize (would go negative here, but test anyway)
        doAnswer(invocation -> {
            Field stackSizeFieldInner = JsonTreeReader.class.getDeclaredField("stackSize");
            stackSizeFieldInner.setAccessible(true);
            int currentSize = stackSizeFieldInner.getInt(spyReader);
            stackSizeFieldInner.setInt(spyReader, currentSize - 1);
            return JsonNull.INSTANCE;
        }).when(spyReader).popStack();

        // Save pathIndices before
        Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
        pathIndicesField.setAccessible(true);
        int[] pathIndicesBefore = (int[]) pathIndicesField.get(spyReader);
        int oldValue = pathIndicesBefore[0];

        // Call nextNull
        spyReader.nextNull();

        // Verify expect and popStack called
        verify(spyReader).expect(JsonToken.NULL);
        verify(spyReader).popStack();

        // pathIndices should not have changed because stackSize was 0 before popStack
        int[] pathIndicesAfter = (int[]) pathIndicesField.get(spyReader);
        assertEquals(oldValue, pathIndicesAfter[0]);

        // stackSize now should be -1 after popStack decrement (edge case)
        Field stackSizeFieldCheck = JsonTreeReader.class.getDeclaredField("stackSize");
        stackSizeFieldCheck.setAccessible(true);
        int stackSizeAfter = stackSizeFieldCheck.getInt(spyReader);
        assertEquals(-1, stackSizeAfter);
    }
}
